import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"發布說明：版本演進 | Antigravity-Manager","description":"了解 Antigravity-Manager 的版本演進方法。在 Settings 頁確認版本並檢查更新，透過 README Changelog 查看修復與提醒，用 /healthz 驗證升級後可用性。","frontmatter":{"title":"發布說明：版本演進 | Antigravity-Manager","sidebarTitle":"3 分鐘看懂版本更新","subtitle":"版本演進：以 README 內嵌 Changelog 為準","description":"了解 Antigravity-Manager 的版本演進方法。在 Settings 頁確認版本並檢查更新，透過 README Changelog 查看修復與提醒，用 /healthz 驗證升級後可用性。","tags":["changelog","release","upgrade","troubleshooting"],"prerequisite":["start-installation","start-proxy-and-first-client"],"order":1},"headers":[],"relativePath":"zh-tw/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md","filePath":"zh-tw/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"}'),n={name:"zh-tw/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"};function l(i,t,d,s,g,h){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="版本演進-以-readme-內嵌-changelog-為準" tabindex="-1">版本演進：以 README 內嵌 Changelog 為準 <a class="header-anchor" href="#版本演進-以-readme-內嵌-changelog-為準" aria-label="Permalink to &quot;版本演進：以 README 內嵌 Changelog 為準&quot;">​</a></h1><p>你準備升級 Antigravity Tools，最怕的不是「沒更新到」，而是「更新了才發現有相容性變化」。這頁把 <strong>Antigravity Tools Changelog（版本演進）</strong> 的閱讀方法講清楚，讓你能在升級前就判斷：這次更新會影響你什麼。</p><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>在 Settings 的 About 頁快速確認目前版本、檢查更新並拿到下載入口</li><li>在 README 的 Changelog 裡只讀對你有影響的版本段落（而不是從頭翻到尾）</li><li>升級前先做一件事：確認是否有「需要你手動改設定/改模型映射」的提醒</li><li>升級後跑一遍最小驗證（<code>/healthz</code>）確認代理還能用</li></ul><h2 id="什麼是-changelog" tabindex="-1">什麼是 Changelog？ <a class="header-anchor" href="#什麼是-changelog" aria-label="Permalink to &quot;什麼是 Changelog？&quot;">​</a></h2><p><strong>Changelog</strong> 是按版本記錄「這次改了什麼」的清單。Antigravity Tools 把它直接寫在 README 的「版本演進」裡，每個版本都會標出日期與關鍵變更。升級前先看 Changelog，能減少踩到相容性變化或回歸問題的機率。</p><h2 id="什麼時候用這一頁" tabindex="-1">什麼時候用這一頁 <a class="header-anchor" href="#什麼時候用這一頁" aria-label="Permalink to &quot;什麼時候用這一頁&quot;">​</a></h2><ul><li>你準備從舊版本升級到新版本，想先確認風險點</li><li>你遇到某個問題（比如 429/0 Token/Cloudflared），想確認它是否在近期版本被修復</li><li>你在團隊裡維護統一版本，需要給同事一個「按版本讀變化」的方法</li></ul><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">建議先把升級路徑準備好</p><p>安裝/升級方式很多（brew、Releases 手動下載、應用程式內更新）。如果你還沒確定自己用哪條路，先看 <strong><a href="/docs/opencodedocs/zh-tw/lbjlaq/Antigravity-Manager/start/installation/">安裝與升級：桌面端最佳安裝路徑（brew / releases）</a></strong>。</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-在-about-頁確認你正在用的版本" tabindex="-1">第 1 步：在 About 頁確認你正在用的版本 <a class="header-anchor" href="#第-1-步-在-about-頁確認你正在用的版本" aria-label="Permalink to &quot;第 1 步：在 About 頁確認你正在用的版本&quot;">​</a></h3><p><strong>為什麼</strong> Changelog 是按版本組織的。你先知道自己目前版本，才知道「要從哪裡開始看」。</p><p>操作路徑：<strong>Settings</strong> → <strong>About</strong>。</p><p><strong>你應該看到</strong>：頁面標題區顯示應用程式名稱與版本號（例如 <code>v3.3.49</code>）。</p><h3 id="第-2-步-點「檢查更新」-拿到最新版本與下載入口" tabindex="-1">第 2 步：點「檢查更新」，拿到最新版本與下載入口 <a class="header-anchor" href="#第-2-步-點「檢查更新」-拿到最新版本與下載入口" aria-label="Permalink to &quot;第 2 步：點「檢查更新」，拿到最新版本與下載入口&quot;">​</a></h3><p><strong>為什麼</strong> 你需要先知道「最新版本號是什麼」，再去 Changelog 裡挑出中間跨過的版本段落。</p><p>在 About 頁點擊「檢查更新」。</p><p><strong>你應該看到</strong>：</p><ul><li>若有更新：提示「new version available」，並出現一個下載按鈕（開啟 <code>download_url</code>）</li><li>若已是最新：提示「latest version」</li></ul><h3 id="第-3-步-去-readme-的-changelog-只看你跨過的版本" tabindex="-1">第 3 步：去 README 的 Changelog 只看你跨過的版本 <a class="header-anchor" href="#第-3-步-去-readme-的-changelog-只看你跨過的版本" aria-label="Permalink to &quot;第 3 步：去 README 的 Changelog 只看你跨過的版本&quot;">​</a></h3><p><strong>為什麼</strong> 你只需要關心「從你目前版本到最新版本之間」的變化，其他歷史版本可以先跳過。</p><p>開啟 README，定位到 <strong>「版本演進 (Changelog)」</strong>，從最新版本開始往下看，直到看到你目前版本為止。</p><p><strong>你應該看到</strong>：版本按 <code>vX.Y.Z (YYYY-MM-DD)</code> 的格式列出，並且每個版本都有分組說明（如核心修復/功能增強）。</p><h3 id="第-4-步-升級後做一次最小驗證" tabindex="-1">第 4 步：升級後做一次最小驗證 <a class="header-anchor" href="#第-4-步-升級後做一次最小驗證" aria-label="Permalink to &quot;第 4 步：升級後做一次最小驗證&quot;">​</a></h3><p><strong>為什麼</strong> 升級後的第一件事不是「跑複雜場景」，而是先確認代理還能正常啟動、能被客戶端探活。</p><p>按 <strong><a href="/docs/opencodedocs/zh-tw/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">啟動本地反代並接入第一個客戶端（/healthz + SDK 設定）</a></strong> 的流程，至少驗證一次 <code>GET /healthz</code>。</p><p><strong>你應該看到</strong>：<code>/healthz</code> 返回成功（用於確認服務可用）。</p><h2 id="近期版本摘要-摘自-readme" tabindex="-1">近期版本摘要（摘自 README） <a class="header-anchor" href="#近期版本摘要-摘自-readme" aria-label="Permalink to &quot;近期版本摘要（摘自 README）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>版本</th><th>日期</th><th>你需要關注的點</th></tr></thead><tbody><tr><td><code>v3.3.49</code></td><td>2026-01-22</td><td>Thinking 中斷與 0 Token 防禦；移除 <code>gemini-2.5-flash-lite</code> 並提醒你手動替換自訂映射；語言/主題等設定即時生效；監控看板增強；OAuth 相容性提升</td></tr><tr><td><code>v3.3.48</code></td><td>2026-01-21</td><td>Windows 平台背景程序靜默執行（修復控制台閃爍）</td></tr><tr><td><code>v3.3.47</code></td><td>2026-01-21</td><td>圖片生成參數映射增強（<code>size</code>/<code>quality</code>）；Cloudflared 隧道支援；修復合併衝突導致的啟動失敗；三層漸進式內容壓縮</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">怎麼快速判斷「這次更新會不會影響我」</p><p>優先找這兩類句子：</p><ul><li><strong>使用者提醒/你需要修改</strong>：比如明確點名某個預設模型被移除，要求你手動調整自訂映射</li><li><strong>核心修復/相容性修復</strong>：比如 0 Token、429、Windows 閃爍、啟動失敗這類「會讓你用不了」的問題</li></ul></div><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>內容</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>README 內嵌 Changelog（版本演進）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/README.md#L324-L455" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>324-455</td></tr><tr><td>About 頁顯示版本號與「檢查更新」按鈕</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L821-L954" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>821-954</td></tr><tr><td>About 頁「檢查更新」指令返回結構</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L187-L215" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>187-215</td></tr><tr><td>自動更新通知（下載並重新啟動）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/UpdateNotification.tsx#L33-L96" target="_blank" rel="noreferrer"><code>src/components/UpdateNotification.tsx</code></a></td><td>33-96</td></tr><tr><td>目前版本號（建置元資料）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/package.json#L1-L4" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>1-4</td></tr></tbody></table></details>',34)])])}const p=a(n,[["render",l]]);export{b as __pageData,p as default};
